import { unstable_cacheTag as cacheTag, revalidateTag } from 'next/cache';
import { redirect } from 'next/navigation';

import { getAllProducts, syncLatestCatalog } from '@/lib/db';

async function getProducts() {
  'use cache';
  cacheTag('products');

  return getAllProducts();
}

export default async function Page() {
  const products = await getProducts();

  return (
    <main style={{ padding: '2rem', fontFamily: 'Arial, sans-serif' }}>
      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          gap: '1rem',
          marginBottom: '2rem'
        }}
      >
        <div>
          <h1 style={{ margin: 0 }}>Admin catalog</h1>
          <p style={{ margin: '0.5rem 0 0', color: '#555' }}>
            Browse cached catalog data and trigger a background sync when ERP/PIM updates land.
          </p>
        </div>

        <form
          action={async () => {
            'use server';

            void syncLatestCatalog().then(() => {
              revalidateTag('products', 'max');
            });

            redirect('/');
          }}
        >
          <button
            type="submit"
            style={{
              border: 0,
              borderRadius: '0.5rem',
              background: '#111827',
              color: '#fff',
              padding: '0.75rem 1rem',
              cursor: 'pointer',
              fontWeight: 600
            }}
          >
            Sync latest catalog
          </button>
        </form>
      </div>

      <section
        style={{
          border: '1px solid #e5e7eb',
          borderRadius: '0.75rem',
          overflow: 'hidden',
          background: '#fff'
        }}
      >
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead style={{ background: '#f9fafb' }}>
            <tr>
              <th style={cellHeaderStyle}>SKU</th>
              <th style={cellHeaderStyle}>Product</th>
              <th style={cellHeaderStyle}>Price</th>
              <th style={cellHeaderStyle}>Inventory</th>
              <th style={cellHeaderStyle}>Availability</th>
            </tr>
          </thead>
          <tbody>
            {products.map((product) => (
              <tr key={product.id}>
                <td style={cellStyle}>{product.sku}</td>
                <td style={cellStyle}>{product.name}</td>
                <td style={cellStyle}>${product.price.toFixed(2)}</td>
                <td style={cellStyle}>{product.inventory}</td>
                <td style={cellStyle}>{product.availability}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </section>
    </main>
  );
}

const cellHeaderStyle: React.CSSProperties = {
  textAlign: 'left',
  padding: '0.75rem 1rem',
  fontSize: '0.875rem',
  color: '#374151',
  borderBottom: '1px solid #e5e7eb'
};

const cellStyle: React.CSSProperties = {
  padding: '0.75rem 1rem',
  borderBottom: '1px solid #e5e7eb'
};

let syncRun = 0;

const baseProducts = [
  { id: 1, sku: 'LAP-1000', name: 'Laptop', price: 999, inventory: 14, availability: 'In stock' },
  { id: 2, sku: 'PHN-2000', name: 'Phone', price: 699, inventory: 32, availability: 'In stock' },
  { id: 3, sku: 'TAB-3000', name: 'Tablet', price: 499, inventory: 0, availability: 'Backorder' },
  { id: 4, sku: 'AUD-4000', name: 'Headphones', price: 199, inventory: 54, availability: 'In stock' },
  { id: 5, sku: 'WAT-5000', name: 'Watch', price: 299, inventory: 9, availability: 'Low stock' }
];

let products = structuredClone(baseProducts);

export async function getAllProducts() {
  await new Promise((resolve) => setTimeout(resolve, 100));
  return structuredClone(products);
}

export async function syncLatestCatalog() {
  await new Promise((resolve) => setTimeout(resolve, 1500));

  syncRun += 1;
  products = baseProducts.map((product, index) => {
    const priceDelta = syncRun * (index + 1) * 3;
    const inventory = Math.max(0, product.inventory + syncRun * 2 - index * 3);

    return {
      ...product,
      price: product.price + priceDelta,
      inventory,
      availability: inventory === 0 ? 'Out of stock' : inventory < 10 ? 'Low stock' : 'In stock'
    };
  });

  return structuredClone(products);
}

import type { Metadata } from 'next';

export const metadata: Metadata = {
  title: 'Admin Catalog',
  description: 'Responsive admin catalog with background sync and cache tag invalidation.'
};

export default function RootLayout({
  children
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html lang="en">
      <body style={{ margin: 0, background: '#f3f4f6' }}>{children}</body>
    </html>
  );
}

